defmodule MyAppWeb.XML.SecureParser do
  @moduledoc """
  Secure XML parser that prevents XXE (XML External Entity) attacks.
  Uses :xmerl with external entities and DTD processing disabled.
  """

  import SweetXml

  @doc """
  Parses XML string securely by disabling external entities and DTDs.
  Returns {:ok, parsed_doc} or {:error, reason}.
  """
  def safe_parse(xml_string) when is_binary(xml_string) do
    # Reject XML with DTD declarations to prevent XXE
    if contains_dtd?(xml_string) do
      {:error, :dtd_not_allowed}
    else
      try do
        # Use xmerl with secure options that disable external entity resolution
        parsed =
          xml_string
          |> String.to_charlist()
          |> :xmerl_scan.string(
            quiet: true,
            # Disable fetching of external entities
            fetch_fun: fn _uri, state -> {:ok, {:string, ''}, state} end,
            # Disable external DTD loading
            rules: :xmerl_scanner,
            acc_fun: &acc_fun/3
          )

        case parsed do
          {xml_element, _rest} -> {:ok, xml_element}
          _ -> {:error, :parse_error}
        end
      rescue
        e -> {:error, {:parse_error, Exception.message(e)}}
      catch
        :exit, reason -> {:error, {:parse_error, inspect(reason)}}
      end
    end
  end

  def safe_parse(_), do: {:error, :invalid_input}

  @doc """
  Safely query parsed XML using xpath.
  """
  def safe_xpath(xml_string, xpath_expr) do
    case safe_parse(xml_string) do
      {:ok, _doc} ->
        # SweetXml's xpath on the original string after validation
        try do
          result = xml_string |> parse(dtd: :none) |> xpath(xpath_expr)
          {:ok, result}
        rescue
          e -> {:error, {:xpath_error, Exception.message(e)}}
        end

      {:error, _} = error ->
        error
    end
  end

  # Check for DTD declarations which could contain entity definitions
  defp contains_dtd?(xml_string) do
    xml_lower = String.downcase(xml_string)

    String.contains?(xml_lower, "<!doctype") or
      String.contains?(xml_lower, "<!entity") or
      String.contains?(xml_lower, "system") and String.contains?(xml_lower, "<!") or
      String.contains?(xml_lower, "<!element")
  end

  defp acc_fun(parsed_entity, acc, global_state) do
    {[parsed_entity | acc], global_state}
  end
end

