defmodule MyAppWeb.SOAPController do
  use MyAppWeb, :controller

  alias MyAppWeb.XML.SecureParser

  import SweetXml

  @max_xml_size 512_000  # 512KB max

  @doc """
  Handle incoming SOAP XML requests securely.
  """
  def handle(conn, %{"_xml" => xml_body}) do
    with :ok <- validate_size(xml_body),
         {:ok, _doc} <- SecureParser.safe_parse(xml_body),
         {:ok, soap_action} <- extract_soap_action(xml_body) do
      process_soap_action(conn, soap_action, xml_body)
    else
      {:error, :dtd_not_allowed} ->
        conn
        |> put_status(400)
        |> put_resp_content_type("application/xml")
        |> text(soap_fault("Client", "DTD declarations are not allowed for security reasons"))

      {:error, :too_large} ->
        conn
        |> put_status(413)
        |> put_resp_content_type("application/xml")
        |> text(soap_fault("Client", "Request body too large"))

      {:error, {:parse_error, reason}} ->
        conn
        |> put_status(400)
        |> put_resp_content_type("application/xml")
        |> text(soap_fault("Client", "Invalid XML: #{inspect(reason)}"))

      {:error, :unknown_action} ->
        conn
        |> put_status(400)
        |> put_resp_content_type("application/xml")
        |> text(soap_fault("Client", "Unknown SOAP action"))

      {:error, reason} ->
        conn
        |> put_status(500)
        |> put_resp_content_type("application/xml")
        |> text(soap_fault("Server", "Internal error: #{inspect(reason)}"))
    end
  end

  def handle(conn, _params) do
    conn
    |> put_status(400)
    |> put_resp_content_type("application/xml")
    |> text(soap_fault("Client", "Expected XML request body"))
  end

  defp validate_size(xml_body) do
    if byte_size(xml_body) > @max_xml_size do
      {:error, :too_large}
    else
      :ok
    end
  end

  defp extract_soap_action(xml_body) do
    case SecureParser.safe_xpath(
           xml_body,
           ~x"//soap:Envelope/soap:Body/*[1]"e
           |> add_namespace("soap", "http://schemas.xmlsoap.org/soap/envelope/")
         ) do
      {:ok, nil} ->
        # Try SOAP 1.2 namespace
        case SecureParser.safe_xpath(
               xml_body,
               ~x"//soap12:Envelope/soap12:Body/*[1]"e
               |> add_namespace("soap12", "http://www.w3.org/2003/05/soap-envelope")
             ) do
          {:ok, nil} -> {:error, :unknown_action}
          {:ok, element} -> {:ok, element}
          error -> error
        end

      {:ok, element} ->
        {:ok, element}

      error ->
        error
    end
  end

  defp process_soap_action(conn, soap_action, xml_body) do
    # Extract the local name of the first child element in the SOAP Body
    action_name =
      case SecureParser.safe_xpath(xml_body, ~x"//soap:Body/*[1]"e |> add_namespace("soap", "http://schemas.xmlsoap.org/soap/envelope/")) do
        {:ok, element} when not is_nil(element) ->
          xml_body
          |> SweetXml.parse(dtd: :none)
          |> xpath(
            ~x"local-name(//soap:Body/*[1])"s
            |> add_namespace("soap", "http://schemas.xmlsoap.org/soap/envelope/")
          )

        _ ->
          "Unknown"
      end

    case action_name do
      "GetUser" ->
        handle_get_user(conn, xml_body)

      "CreateOrder" ->
        handle_create_order(conn, xml_body)

      _ ->
        conn
        |> put_status(400)
        |> put_resp_content_type("application/xml")
        |> text(soap_fault("Client", "Unsupported SOAP action: #{action_name}"))
    end
  end

  defp handle_get_user(conn, xml_body) do
    # Safely extract user ID from the request
    {:ok, user_id} =
      SecureParser.safe_xpath(
        xml_body,
        ~x"//GetUser/UserId/text()"s
      )

    # Sanitize the extracted value
    sanitized_id = sanitize_input(user_id)

    response = """
    <?xml version="1.0" encoding="UTF-8"?>
    <soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
      <soap:Body>
        <GetUserResponse>
          <UserId>#{escape_xml(sanitized_id)}</UserId>
          <Name>Example User</Name>
        </GetUserResponse>
      </soap:Body>
    </soap:Envelope>
    """

    conn
    |> put_resp_content_type("application/xml")
    |> text(response)
  end

  defp handle_create_order(conn, _xml_body) do
    response = """
    <?xml version="1.0" encoding="UTF-8"?>
    <soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
      <soap:Body>
        <CreateOrderResponse>
          <Status>Created</Status>
        </CreateOrderResponse>
      </soap:Body>
    </soap:Envelope>
    """

    conn
    |> put_resp_content_type("application/xml")
    |> text(response)
  end

  defp soap_fault(fault_code, fault_string) do
    """
    <?xml version="1.0" encoding="UTF-8"?>
    <soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
      <soap:Body>
        <soap:Fault>
          <faultcode>soap:#{escape_xml(fault_code)}</faultcode>
          <faultstring>#{escape_xml(fault_string)}</faultstring>
        </soap:Fault>
      </soap:Body>
    </soap:Envelope>
    """
  end

  defp escape_xml(string) when is_binary(string) do
    string
    |> String.replace("&", "&amp;")
    |> String.replace("<", "&lt;")
    |> String.replace(">", "&gt;")
    |> String.replace("\"", "&quot;")
    |> String.replace("'", "&apos;")
  end

  defp escape_xml(other), do: escape_xml(to_string(other))

  defp sanitize_input(input) when is_binary(input) do
    input
    |> String.trim()
    |> String.slice(0, 1000)
  end

  defp sanitize_input(other), do: sanitize_input(to_string(other))
end

